#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
using namespace std;
const int N=2e4+5,INF=2e9;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
int s[N],d[N],tot,deq[N],h=1,t;
inline double Cnt(int a,int b){return 1.0*(d[b]*s[b]-d[a]*s[a])/(s[a]-s[b]);}
int main()
{
	int n=read();rep(1,n,i)s[i]=s[i-1]+read(),tot+=s[i]*(d[i]=read());
	int ans=INF;drep(n-1,1,i)d[i]+=d[i+1]; rep(1,n,i)
	{
		while(h<t&&Cnt(deq[h],deq[h+1])<-d[i])h++;
		ans=min(ans,tot-d[deq[h]]*s[deq[h]]-d[i]*s[i]+d[i]*s[deq[h]]);
		while(h<t&&Cnt(deq[t-1],deq[t])>Cnt(deq[t],i))t--;deq[++t]=i;
	}
	printf("%d",ans);
}
